// Captura __trace_id UNA vez — referenciar desde span para evitar divergencia con Date.now()
// R4: startTime también capturado aquí para latencia del span LLM.
const fincaId = $input.first().json.finca_id;
const ts = new Date().toISOString();
return [{ json: { ...$input.first().json, __trace_id: 'reporte-' + fincaId + '-' + ts, __t0_resumen: ts } }];

