INSERT INTO reportes_semanales (finca_id, fecha_inicio, fecha_fin, eventos_incluidos, resumen_texto, enviado_at)
VALUES ($1, NOW() - INTERVAL '7 days', NOW(), $2, $3, NOW())
RETURNING id;

